var row = (data && data[0] && data[0][0]) ? data[0][0] : {}

var usage       = parseInt(row['usage']) || 0
var allocatable = parseInt(row['allocatable_capacity']) || 0
var free        = Math.max(allocatable - usage, 0)
var usagePct    = allocatable > 0 ? ((usage / allocatable) * 100).toFixed(1) : 0

option = {
  title: {
    text: 'Pod Capacity',
    subtext: 'Allocatable: ' + allocatable + '  |  Used: ' + usagePct + '%',
    left: 'center'
  },
  tooltip: { trigger: 'item' },
  legend: {
    orient: 'horizontal',
    bottom: 0,
    left: 'center'
  },
  series: [
    {
      name: 'Pods',
      type: 'pie',
      radius: '50%',
      center: ['50%', '45%'],
