var allRows = (data && data[0]) ? data[0] : []
var PAGE_SIZE = 8
var totalPages = Math.ceil(allRows.length / PAGE_SIZE)

// Find dataset max for xAxis scale and relative coloring
var maxVal = 0
for (var i = 0; i < allRows.length; i++) {
  var v = parseFloat(allRows[i]['cpu_mcores']) || 0
  if (v > maxVal) maxVal = v
}
var xMax = Math.ceil(maxVal / 100) * 100

var pageOptions = []
for (var pageIdx = 0; pageIdx < totalPages; pageIdx++) {
  var start = pageIdx * PAGE_SIZE
  var pageRows = allRows.slice(start, start + PAGE_SIZE)

  var pods = pageRows.map(function(r) {
    var name = r['k8s_pod_name'] || ''
    return name.length > 38 ? name.substring(0, 38) + '...' : name
  })

  var bars = []
  for (var i = 0; i < pageRows.length; i++) {
    var v = parseFloat(pageRows[i]['cpu_mcores']) || 0
    var rel = maxVal > 0 ? v / maxVal : 0
    bars.push({
      value: v,
      label: {
        show: true, position: 'right',
        formatter: v.toFixed(1) + 'm',
        fontSize: 12, color: '#333'
      },
      itemStyle: {
        color: rel > 0.75 ? '#e6474a' : rel > 0.4 ? '#f5a623' : '#52c41a'
      }
    })
  }

  var startNum = start + 1
  var endNum = Math.min(start + PAGE_SIZE, allRows.length)
  pageOptions.push({
    title: {
      text: 'Showing ' + startNum + '–' + endNum + ' of ' + allRows.length + ' pods  |  CPU Usage (millicores)',
      textStyle: { fontSize: 11, color: '#888', fontWeight: 'normal' },
      left: 'center', top: 4
    },
    yAxis: { data: pods },
    series: [{ data: bars }]
  })
}

var pageLabels = []
for (var p = 0; p < totalPages; p++) { pageLabels.push(String(p + 1)) }

option = {
  baseOption: {
    timeline: {
      data: pageLabels,
      axisType: 'category',
      autoPlay: false,
      symbol: 'none',
      lineStyle: { show: false },
      label: { color: '#666', fontSize: 11 },
      checkpointStyle: { color: '#5470c6', borderColor: '#5470c6', symbol: 'roundRect', symbolSize: [22, 20] },
      controlStyle: { show: true, showPlayBtn: false, showPrevBtn: true, showNextBtn: true, itemSize: 16, itemGap: 8, color: '#5470c6', borderColor: '#5470c6' },
      itemStyle: { color: '#eee', borderColor: '#ddd' },
      emphasis: { itemStyle: { color: '#5470c6' }, label: { color: '#fff', fontWeight: 'bold' } },
      height: 32, bottom: 0, padding: [0, 40]
    },
    grid: { top: 30, bottom: 48, left: '35%', right: '12%', containLabel: false },
    xAxis: {
      type: 'value',
      max: xMax,
      axisLabel: { formatter: '{value}m' },
      splitLine: { lineStyle: { color: '#f0f0f0' } }
    },
    yAxis: {
      type: 'category',
      inverse: true,
      axisTick: { show: false },
      axisLine: { show: false },
      axisLabel: { fontSize: 11 }
    },
    series: [{ type: 'bar', barWidth: '60%' }]
  },
  options: pageOptions
}

