var allRows = (data && data[0]) ? data[0] : []
var PAGE_SIZE = 8
var totalPages = Math.ceil(allRows.length / PAGE_SIZE)

// Build one option per page
var pageOptions = []
for (var pageIdx = 0; pageIdx < totalPages; pageIdx++) {
  var start = pageIdx * PAGE_SIZE
  var pageRows = allRows.slice(start, start + PAGE_SIZE)
  var pods = pageRows.map(function(r) { return r['k8s_pod_name'] })
  var pcts = pageRows.map(function(r) { return parseFloat(r['utilization_pct']) * 100 || 0 })

  var ref = []
  var bars = []
  for (var i = 0; i < pcts.length; i++) {
    var v = pcts[i]
    ref.push({ value: 100 })
    bars.push({
      value: Math.min(v, 100),
      label: { show: true, position: 'right', formatter: v.toFixed(2) + '%', fontSize: 12, color: '#333' },
      itemStyle: { color: v > 90 ? '#e6474a' : v > 50 ? '#f5a623' : '#52c41a' }
    })
  }

  var startNum = start + 1
  var endNum = Math.min(start + PAGE_SIZE, allRows.length)
  pageOptions.push({
    title: { text: 'Showing ' + startNum + '–' + endNum + ' of ' + allRows.length + ' pods', textStyle: { fontSize: 11, color: '#888', fontWeight: 'normal' }, left: 'center', top: 4 },
    yAxis: { data: pods },
    series: [{ data: ref }, { data: bars }]
  })
}

