for (var pageIdx = 0; pageIdx < totalPages; pageIdx++) {
  var start = pageIdx * PAGE_SIZE
  var pageRows = allRows.slice(start, start + PAGE_SIZE)

  // Show "pod (namespace)" on y-axis
  var pods = pageRows.map(function(r) {
    var name = r['pod'] || ''
    var ns = r['namespace'] ? ' (' + r['namespace'] + ')' : ''
    var label = name + ns
    return label.length > 42 ? label.substring(0, 42) + '...' : label
  })

  var pcts = pageRows.map(function(r) { return parseFloat(r['cpu_usage_pct']) || 0 })

  var ref = []
  var bars = []
  for (var i = 0; i < pcts.length; i++) {
    var v = pcts[i]
    ref.push({ value: 100 })
    bars.push({
      value: Math.min(v, 100),
      label: {
        show: true, position: 'right',
        formatter: v > 100 ? v.toFixed(2) + '% (over limit)' : v.toFixed(2) + '%',
        fontSize: 12, color: '#333'
      },
      itemStyle: { color: v > 90 ? '#e6474a' : v > 50 ? '#f5a623' : '#52c41a' }
    })
  }

  var startNum = start + 1
  var endNum = Math.min(start + PAGE_SIZE, allRows.length)
  pageOptions.push({
    title: {
      text: 'Showing ' + startNum + '–' + endNum + ' of ' + allRows.length + ' pods  |  CPU Usage vs Limit',
      textStyle: { fontSize: 11, color: '#888', fontWeight: 'normal' },
      left: 'center', top: 4
    },
    yAxis: { data: pods },
    series: [{ data: ref }, { data: bars }]
  })
}

